const rows = $input.all();
const output = [];

if (!rows || rows.length === 0) {
  output.push({ json: { message: ':white_check_mark: *Aging Tickets Report* -- No open/pending tickets older than 7 days today!' } });
  return output;
}

const today = new Date().toISOString().slice(0, 10);

const lines = rows.map(function(item) {
  const r = item.json;
  const accountName = r.account_name || 'Unknown';
  const segment = r.account_segment ? ' (' + r.account_segment + ')' : '';
  const count = Number(r.ticket_count);
  const oldest = r.oldest_ticket_date ? String(r.oldest_ticket_date).slice(0, 10) : 'N/A';
  const agents = r.assignees || 'Unassigned';
  return '- *' + accountName + '*' + segment + ' -- ' + count + ' ticket' + (count > 1 ? 's' : '') + ' | Oldest: ' + oldest + ' | Agents: ' + agents;
});

const total = rows.reduce(function(sum, item) {
  return sum + Number(item.json.ticket_count || 0);
}, 0);

const header = ':rotating_light: *Aging Tickets Report* -- Open/Pending > 7 days\n:calendar: Run date: ' + today + ' | ' + rows.length + ' accounts | ' + total + ' total tickets';

const message = header + '\n\n' + lines.join('\n');

output.push({ json: { message: message } });
return output;
